import{_ as t,c as e,R as i,G as o,w as r,B as n,o as c,a as s}from"./chunks/framework.CxmQoMhV.js";const _=JSON.parse('{"title":"共享模型--管程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/笔记/java/thread/sharedModel.md","filePath":"docs/笔记/java/thread/sharedModel.md"}'),d={name:"docs/笔记/java/thread/sharedModel.md"};function h(u,a,p,b,f,m){const l=n("font");return c(),e("div",null,[a[1]||(a[1]=i('<h1 id="共享模型-管程" tabindex="-1">共享模型--管程 <a class="header-anchor" href="#共享模型-管程" aria-label="Permalink to &quot;共享模型--管程&quot;">​</a></h1><h2 id="_1-临界区-critical-section" tabindex="-1">1. 临界区 Critical Section <a class="header-anchor" href="#_1-临界区-critical-section" aria-label="Permalink to &quot;1. 临界区 Critical Section&quot;">​</a></h2><ul><li>一个程序运行多个线程本身是没有问题的</li><li>问题出在多个线程访问共享资源 <ul><li>多个线程读共享资源其实也没有问题</li><li>在多个线程对共享资源读写操作时发生指令交错，就会出现问题</li></ul></li><li>一段代码块内如果存在对共享资源的多线程读写操作，称这段代码块为临界区</li></ul><h2 id="_2-竞态条件-race-condition" tabindex="-1">2. 竞态条件 Race Condition <a class="header-anchor" href="#_2-竞态条件-race-condition" aria-label="Permalink to &quot;2. 竞态条件 Race Condition&quot;">​</a></h2><ul><li>多个线程在临界区内执行，由于代码的执行序列不同而导致结果无法预测，称之为发生了竞态条件</li></ul><h2 id="_3-解决方案" tabindex="-1">3. 解决方案 <a class="header-anchor" href="#_3-解决方案" aria-label="Permalink to &quot;3. 解决方案&quot;">​</a></h2><h3 id="_3-1-synchronized-解决方案" tabindex="-1">3.1. synchronized 解决方案 <a class="header-anchor" href="#_3-1-synchronized-解决方案" aria-label="Permalink to &quot;3.1. synchronized 解决方案&quot;">​</a></h3>',7)),o(l,{color:"33FF33"},{default:r(()=>a[0]||(a[0]=[s("为了避免临界区的竞态条件发生 ")])),_:1}),a[2]||(a[2]=i(' <ul><li>阻塞式的解决方案：synchronized，Lock <ul><li>synchronized，来解决上述问题，即俗称的【对象锁】，它采用互斥的方式让同一时刻至多只有一个线程能持有【对象锁】，其它线程再想获取这个【对象锁】时就会阻塞住。这样就能保证拥有锁的线程可以安全的执行临界区内的代码，不用担心线程上下文切换.</li></ul><div class="tip custom-block"><p class="custom-block-title">**</p><p>虽然 java 中互斥和同步都可以采用 synchronized 关键字来完成，但它们还是有区别的：</p><ul><li>互斥是保证临界区的竞态条件发生，同一时刻只能有一个线程执行临界区代码</li><li>同步是由于线程执行的先后、顺序不同、需要一个线程等待其它线程运行到某个点<br> synchronized 实际是用对象锁保证了临界区内代码的原子性，临界区内的代码对外是不可分割的，不会被线程切换所打断。</li></ul></div></li><li>非阻塞式的解决方案：原子变量</li></ul><h2 id="_4-变量的线程安全分析" tabindex="-1">4. 变量的线程安全分析 <a class="header-anchor" href="#_4-变量的线程安全分析" aria-label="Permalink to &quot;4. 变量的线程安全分析&quot;">​</a></h2><h3 id="_4-1-成员变量和静态变量是否线程安全" tabindex="-1">4.1. 成员变量和静态变量是否线程安全？ <a class="header-anchor" href="#_4-1-成员变量和静态变量是否线程安全" aria-label="Permalink to &quot;4.1. 成员变量和静态变量是否线程安全？&quot;">​</a></h3><ul><li>如果它们没有共享，则线程安全</li><li>如果它们被共享了，根据它们的状态是否能够改变，又分两种情况 <ul><li>如果只有读操作，则线程安全</li><li>如果有读写操作，则这段代码是临界区，需要考虑线程安全</li></ul></li></ul><h3 id="_4-2-局部变量是否线程安全" tabindex="-1">4.2. 局部变量是否线程安全？ <a class="header-anchor" href="#_4-2-局部变量是否线程安全" aria-label="Permalink to &quot;4.2. 局部变量是否线程安全？&quot;">​</a></h3><ul><li>局部变量是线程安全的</li><li>但局部变量引用的对象则未必 <ul><li>如果该对象没有逃离方法的作用访问，它是线程安全的</li><li>如果该对象逃离方法的作用范围，需要考虑线程安全</li></ul></li></ul><h3 id="_4-3-常见线程安全类" tabindex="-1">4.3. 常见线程安全类 <a class="header-anchor" href="#_4-3-常见线程安全类" aria-label="Permalink to &quot;4.3. 常见线程安全类&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">常见线程安全类</p><p>String Integer StringBuffer Random Vector Hashtable java.util.concurrent 包下的类</p><p>这里说它们是线程安全的是指，多个线程调用它们同一个实例的某个方法时，是线程安全的 它们的每个方法是原子的 但注意它们多个方法的组合不是原子的</p></div><h3 id="_4-4-wait-notify" tabindex="-1">4.4. wait / notify <a class="header-anchor" href="#_4-4-wait-notify" aria-label="Permalink to &quot;4.4. wait / notify&quot;">​</a></h3><h4 id="_4-4-1-api-介绍" tabindex="-1">4.4.1. API 介绍 <a class="header-anchor" href="#_4-4-1-api-介绍" aria-label="Permalink to &quot;4.4.1. API 介绍&quot;">​</a></h4><ul><li>obj.wait() 让进入 object 监视器的线程到 waitSet 等待</li><li>obj.notify() 在 object 上正在 waitSet 等待的线程中挑一个唤醒</li><li>obj.notifyAll() 让 object 上正在 waitSet 等待的线程全部唤醒<div class="tip custom-block"><p class="custom-block-title">TIP</p><p>wait() 方法会释放对象的锁，进入 WaitSet 等待区，从而让其他线程就机会获取对象的锁。无限制等待，直到notify 为止<br> wait(long n) 有时限的等待, 到 n 毫秒后结束等待，或是被 notify</p></div></li></ul><div class="tip custom-block"><p class="custom-block-title">sleep(long n) 和 wait(long n) 的区别</p><ol><li>sleep 是 Thread 方法，而 wait 是 Object 的方法</li><li>sleep 不需要强制和 synchronized 配合使用，但 wait 需要 和 synchronized 一起用</li><li>sleep 在睡眠的同时，不会释放对象锁的，但 wait 在等待的时候会释放对象锁</li><li>它们 状态 TIMED_WAITING</li></ol></div><div class="tip custom-block"><p class="custom-block-title">1</p><p>notify 只能随机唤醒一个 WaitSet 中的线程，这时如果有其它线程也在等待，那么就可能唤醒不了正确的线程，称之为【虚假唤醒】<br> 解决方法，改为 notifyAll</p></div><div class="tip custom-block"><p class="custom-block-title">2</p><p>用 notifyAll 仅解决某个线程的唤醒问题，但使用 if + wait 判断仅有一次机会，一旦条件不成立，就没有重新判断的机会了<br> 解决方法，用 while + wait，当条件不成立，再次 wait</p></div><h3 id="_4-5-park-unpark" tabindex="-1">4.5. Park &amp; Unpark <a class="header-anchor" href="#_4-5-park-unpark" aria-label="Permalink to &quot;4.5. Park &amp; Unpark&quot;">​</a></h3><h4 id="_4-5-1-与-object-的-wait-notify-相比" tabindex="-1">4.5.1. 与 Object 的 wait &amp; notify 相比 <a class="header-anchor" href="#_4-5-1-与-object-的-wait-notify-相比" aria-label="Permalink to &quot;4.5.1. 与 Object 的 wait &amp; notify 相比&quot;">​</a></h4><ul><li>wait，notify 和 notifyAll 必须配合 Object Monitor 一起使用，而 park，unpark 不必</li><li>park &amp; unpark 是以线程为单位来【阻塞】和【唤醒】线程，而 notify 只能随机唤醒一个等待线程，notifyAll 是唤醒所有等待线程，就不那么【精确】</li><li>park &amp; unpark 可以先 unpark，而 wait &amp; notify 不能先 notify</li></ul>',18))])}const y=t(d,[["render",h]]);export{_ as __pageData,y as default};
